INSERT INTO scenarios (id, slug, category, title, description) VALUES
('ed269f35-0b9e-4478-a627-7d926400f8df', 'the-bag-from-2021-trading-psychosynt-0', 'trading', 'The bag from 2021 (trading)', 'A position down 40% has been dead money for years. Tax-loss season is here. Cutting it admits the mistake; holding keeps the hope alive. There is no clean option.'),
('0da37ec9-f03b-4149-8633-ac11ab1ff112', 'the-leaked-number-negotiation-psychosynt-1', 'negotiation', 'The leaked number (negotiation)', 'You now know, through a channel you should not have, roughly what the other side''s ceiling is. Using it tips your hand about how you know; not using it wastes real leverage.'),
('62098f12-4ebf-4fe9-8a40-7309b098da13', 'the-subtweet-social-psychosynt-2', 'social', 'The subtweet (social)', 'Someone is clearly talking about you without naming you, in a space where everyone else can tell. Responding confirms it landed; ignoring it looks like guilt.'),
('fa526a7d-7015-4457-acd5-3949f0c9c280', 'successor-gap-crisis-psychosynt-3', 'crisis', 'Successor gap (crisis)', 'The one person who understands this system is unreachable and the workaround they mentioned once was never written down.'),
('af2d91c8-2519-4d60-b3b1-54279996161b', 'parabolic-breakout-trading-psychosynt-4', 'trading', 'Parabolic breakout (trading)', 'A name you passed on is up 42% in three sessions and every feed is screaming about it. Sizing in now means chasing; sitting out means watching it run. There is no clean option.'),
('1e58ca6d-5e1c-4679-b150-7f97c46ed374', 'public-negotiation-negotiation-psychosynt-5', 'negotiation', 'Public negotiation (negotiation)', 'The terms are being negotiated with a journalist or the internet watching in real time. Every concession becomes a headline before the deal is done. The clock is running.'),
('6a0adcae-fbd9-4261-96c8-889f3dd7c217', 'secondhand-secret-social-psychosynt-6', 'social', 'Secondhand secret (social)', 'You were told something in confidence that directly affects a decision someone else is about to make. Staying silent lets them walk into it.'),
('bfa86fd6-83de-4477-926d-9ac0c7075554', 'regulatory-clock-crisis-psychosynt-7', 'crisis', 'Regulatory clock (crisis)', 'A regulator wants an answer by end of day that would normally take a week to responsibly produce. Rushing it and stalling it both carry real exposure. There is no clean option.'),
('75933aed-5df3-475c-9db1-84917d77359c', 'illiquid-exit-trading-psychosynt-8', 'trading', 'Illiquid exit (trading)', 'You need out of a thinly traded name, but your own selling moves the price. Dumping fast eats slippage; scaling out risks the news breaking first.'),
('7408fcc9-0094-455e-8bf9-6214902139df', 'the-manufactured-deadline-negotiation-psychosynt-9', 'negotiation', 'The manufactured deadline (negotiation)', 'They insist a decision is needed by end of day for reasons that do not quite add up. Rushing favors them; stalling may cost you leverage.'),
('bfff1e8e-e534-4aef-ab95-6077f69880d6', 'public-callout-social-psychosynt-10', 'social', 'Public callout (social)', 'Someone criticizes your decision in front of the whole group, and all eyes turn to you. Defending looks defensive; conceding looks weak. There is no clean option.'),
('9fc882db-0b56-42ec-a3ed-8dfaf9171759', 'regulatory-clock-crisis-psychosynt-11', 'crisis', 'Regulatory clock (crisis)', 'A regulator wants an answer by end of day that would normally take a week to responsibly produce. Rushing it and stalling it both carry real exposure. Everyone is watching how you handle it.'),
('2380e8fe-4eef-4665-8619-7f0219a10e12', 'rate-decision-surprise-trading-psychosynt-12', 'trading', 'Rate decision surprise (trading)', 'The central bank just did the opposite of what the market priced in. Every model in front of you is instantly stale, and the tape is moving faster than you can think. There is no clean option.'),
('0351dc7e-49bc-4ae9-b86f-1d0acb538253', 'absurd-anchor-negotiation-psychosynt-13', 'negotiation', 'Absurd anchor (negotiation)', 'They open with a figure so far from reality it is almost insulting. Countering hard risks blowing up rapport; splitting the difference rewards the tactic.'),
('cd9295bc-7f23-40f3-8785-46a6057bafdc', 'group-chat-archaeology-social-psychosynt-14', 'social', 'Group chat archaeology (social)', 'Someone digs up an old message of yours and reads it in the worst possible light to the group. Context helps but sounds like an excuse. Everyone is watching how you handle it.'),
('be1701e4-ec13-45dd-80bd-5a40f92e044d', 'contradicting-experts-crisis-psychosynt-15', 'crisis', 'Contradicting experts (crisis)', 'Two credentialed advisors are giving you opposite recommendations with equal confidence, and the decision cannot wait for a tiebreaker. There is no clean option.'),
('78d34749-5176-4e79-8928-af0c0eb44cba', 'overnight-gap-down-trading-psychosynt-16', 'trading', 'Overnight gap-down (trading)', 'A core position gaps down 56% overnight on an unverified headline. Your stop was set at -10% but the market never printed there, and the open is minutes away. Everyone is watching how you handle it.'),
('d9b7d3c0-889a-47fe-a888-57d2f3bcefbc', 'translation-gap-negotiation-psychosynt-17', 'negotiation', 'Translation gap (negotiation)', 'A cultural or linguistic gap means you cannot tell if the last answer was a firm no or an opening. Pressing for clarity might itself read as rude. Everyone is watching how you handle it.'),
('22709a7a-9d74-484c-abed-e2b75369d232', 'awkward-reunion-social-psychosynt-18', 'social', 'Awkward reunion (social)', 'You run into someone you have not fully patched things up with, in front of people who do not know the history. Everyone is watching how normal you can make this look. There is no clean option.'),
('97ebfb79-9132-4bd8-a8e7-3002f008f4bc', 'missing-teammate-crisis-psychosynt-19', 'crisis', 'Missing teammate (crisis)', 'A key person has gone dark before a critical handoff and no one can reach them. Covering for them buys time; escalating exposes them. There is no clean option.'),
('653e0ea5-2e64-49c6-99db-b820746e00bd', 'illiquid-exit-trading-psychosynt-20', 'trading', 'Illiquid exit (trading)', 'You need out of a thinly traded name, but your own selling moves the price. Dumping fast eats slippage; scaling out risks the news breaking first. The clock is running.'),
('ad219b7b-295f-479e-a039-07228261ee13', 'reopened-terms-negotiation-psychosynt-21', 'negotiation', 'Reopened terms (negotiation)', 'A point you thought was settled gets pried back open at the eleventh hour. Conceding keeps the deal alive; refusing risks the whole thing collapsing.'),
('cb917d79-e7f0-4700-92f3-33701c9f769b', 'viral-misread-social-psychosynt-22', 'social', 'Viral misread (social)', 'A throwaway message of yours is being screenshotted and reframed out of context. Explaining fuels it; ignoring lets it harden into fact. The clock is running.'),
('492877e0-ddb3-4667-aef9-dd636467298e', 'the-false-alarm-cost-crisis-psychosynt-23', 'crisis', 'The false alarm cost (crisis)', 'The last three times you escalated this class of incident, it was nothing — and escalating costs real credibility. This one looks the same. Is it? Everyone is watching how you handle it.'),
('0d584868-e151-4dee-b343-a378f5795a19', 'rate-decision-surprise-trading-psychosynt-24', 'trading', 'Rate decision surprise (trading)', 'The central bank just did the opposite of what the market priced in. Every model in front of you is instantly stale, and the tape is moving faster than you can think. Everyone is watching how you handle it.'),
('f5fb4529-471f-420a-855d-28376e85c8b7', 'silent-counterpart-negotiation-psychosynt-25', 'negotiation', 'Silent counterpart (negotiation)', 'After your offer, the other side simply goes quiet and lets the silence stretch. Filling it usually means negotiating against yourself. The clock is running.'),
('0d0c4d8c-0052-4d78-8010-bc5864706351', 'public-callout-social-psychosynt-26', 'social', 'Public callout (social)', 'Someone criticizes your decision in front of the whole group, and all eyes turn to you. Defending looks defensive; conceding looks weak. The clock is running.'),
('49302f43-c830-4f49-b203-d8fe658bd3e2', 'vendor-collapse-crisis-psychosynt-27', 'crisis', 'Vendor collapse (crisis)', 'A critical vendor just went under with no notice and no handoff plan. Every downstream commitment you made assumed they would still exist tomorrow. Everyone is watching how you handle it.'),
